using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and communication." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and their impact on the present." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers and holds three patents in natural language processing.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Miller", Title = "Associate Professor of Mathematics", Bio = "Dr. Miller's research focuses on combinatorics and graph theory. He has been teaching for 15 years and received the Distinguished Teaching Award in 2022.", Email = "j.miller@university.edu" },
            new() { Id = 3, Name = "Prof. Emily Carter", Title = "Professor of English", Bio = "Prof. Carter is an expert in contemporary American literature. She is the author of three books on postmodern fiction and a frequent contributor to literary journals.", Email = "e.carter@university.edu" },
            new() { Id = 4, Name = "Dr. Robert Park", Title = "Professor of Physics", Bio = "Dr. Park conducts research in quantum mechanics and particle physics. He previously worked at CERN and has mentored over 20 PhD students.", Email = "r.park@university.edu" },
            new() { Id = 5, Name = "Dr. Maria Gonzalez", Title = "Associate Professor of History", Bio = "Dr. Gonzalez specializes in Latin American history and colonial studies. She leads the university's oral history project and has conducted fieldwork in five countries.", Email = "m.gonzalez@university.edu" },
            new() { Id = 6, Name = "Dr. Alan Turing Jr.", Title = "Assistant Professor of Computer Science", Bio = "Dr. Turing focuses on cybersecurity and distributed systems. Before joining academia, he worked as a senior engineer at a major tech company.", Email = "a.turing@university.edu" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "An introductory course covering programming fundamentals using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Room = "Science Hall 201", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 301", Title = "Data Structures & Algorithms", Description = "Advanced study of data structures including trees, graphs, and hash tables. Algorithm design techniques such as divide-and-conquer, dynamic programming, and greedy algorithms.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Room = "Science Hall 305", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = false },
            new() { Id = 3, Code = "CS 450", Title = "Cybersecurity Fundamentals", Description = "Introduction to information security principles, cryptography, network security, and ethical hacking. Includes hands-on lab exercises.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Room = "Tech Building 110", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[5], IsFeatured = true },
            new() { Id = 4, Code = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, determinants, and eigenvalues. Applications to computer graphics and data science.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Room = "Math Building 102", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1], IsFeatured = false },
            new() { Id = 5, Code = "MATH 310", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis. Emphasis on real-world applications.", Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", Room = "Math Building 205", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 6, Code = "ENG 110", Title = "Academic Writing", Description = "Develop skills in critical reading, argumentation, and academic essay writing. Students produce multiple drafts with peer and instructor feedback.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Room = "Humanities 301", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 7, Code = "ENG 350", Title = "American Literature: 1900–Present", Description = "Survey of major American literary works from the twentieth and twenty-first centuries. Authors include Fitzgerald, Morrison, Pynchon, and Díaz.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", Room = "Humanities 215", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introductory physics with weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:00 PM", Room = "Physics Lab 100", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = true },
            new() { Id = 9, Code = "PHYS 420", Title = "Quantum Mechanics", Description = "Wave functions, Schrödinger equation, quantum operators, angular momentum, and spin. Prerequisites: PHYS 301, MATH 301.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", Room = "Physics Lab 302", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = false },
            new() { Id = 10, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, cultural exchanges, and transformative events from antiquity through the late medieval period.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", Room = "Liberal Arts 405", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[4], IsFeatured = false },
            new() { Id = 11, Code = "HIST 330", Title = "Latin American Revolutions", Description = "Examination of revolutionary movements in Latin America from the 18th century to the present, including independence movements and 20th-century social revolutions.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", Room = "Liberal Arts 210", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[4], IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();
}

