@page "/courses"
@rendermode InteractiveServer
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartment">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (filteredCourses.Count == 0)
{
    <p class="text-muted">No courses match your search criteria.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in filteredCourses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.Department.Name</td>
                        <td>@course.Credits</td>
                        <td>@course.Instructor.Name</td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

<p class="text-muted">Showing @filteredCourses.Count of @totalCourses courses</p>

@code {
    private List<UniversityCourseCatalog.Models.Department> departments = new();
    private List<UniversityCourseCatalog.Models.Course> filteredCourses = new();
    private int totalCourses;

    private string _searchTerm = "";
    private string searchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; FilterCourses(); }
    }

    private int _selectedDepartment;
    private int selectedDepartment
    {
        get => _selectedDepartment;
        set { _selectedDepartment = value; FilterCourses(); }
    }

    [SupplyParameterFromQuery(Name = "department")]
    public int? DepartmentFromQuery { get; set; }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        totalCourses = CatalogService.GetAllCourses().Count;

        if (DepartmentFromQuery.HasValue)
            _selectedDepartment = DepartmentFromQuery.Value;

        FilterCourses();
    }

    private void FilterCourses()
    {
        int? deptFilter = _selectedDepartment > 0 ? _selectedDepartment : null;
        filteredCourses = CatalogService.SearchCourses(
            string.IsNullOrWhiteSpace(_searchTerm) ? null : _searchTerm,
            deptFilter);
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course. You will receive a confirmation via your university email.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@model.Name</strong>. Your enrollment request for
            <strong>@(selectedCourse?.Code): @(selectedCourse?.Title)</strong>
            has been received. You will be notified of your enrollment status via email.</p>
        <a href="enroll" class="btn btn-outline-success">Submit Another Request</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8 col-lg-6">
            <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="name" class="form-label">Full Name</label>
                    <InputText id="name" class="form-control" @bind-Value="model.Name" />
                    <ValidationMessage For="() => model.Name" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" />
                    <ValidationMessage For="() => model.StudentId" />
                    <div class="form-text">Your alphanumeric student ID (e.g., STU12345).</div>
                </div>

                <div class="mb-3">
                    <label for="course" class="form-label">Course</label>
                    <InputSelect id="course" class="form-select" @bind-Value="model.CourseId">
                        <option value="0">-- Select a Course --</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code: @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.CourseId" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private UniversityCourseCatalog.Models.EnrollmentRequest model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "course")]
    public int? PreselectedCourseId { get; set; }

    private List<UniversityCourseCatalog.Models.Course> courses = new();
    private UniversityCourseCatalog.Models.Course? selectedCourse;
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();

        if (PreselectedCourseId.HasValue && model.CourseId == 0)
            model.CourseId = PreselectedCourseId.Value;
    }

    private void HandleSubmit()
    {
        selectedCourse = CatalogService.GetCourse(model.CourseId);
        submitted = true;
    }
}

