                    <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" />
                    <ValidationMessage For="() => model.StudentId" />
                    <div class="form-text">Your alphanumeric student ID (e.g., STU12345).</div>
                </div>

                <div class="mb-3">
                    <label for="course" class="form-label">Course</label>
                    <InputSelect id="course" class="form-select" @bind-Value="model.CourseId">
                        <option value="0">-- Select a Course --</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code: @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.CourseId" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Request</button>
            </EditForm>
        </div>
    </div>
}

